INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2, 1, "ペコリーヌとの出会い", "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 91002, 5118061, "青空の下で謁見", 40, 8, 2834, 7, 10118, "フリーマーケット会場", 20063115, 0);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2, 1, "マホとの出会い", "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 91002, 5118062, "未来の騎空団\nマスコット？", 40, 8, 2835, 7, 10118, "フリーマーケット会場", 20063115, 0);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2, 1, "アキノとの出会い", "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 91002, 5118063, "お嬢さまからの\n緊急依頼", 40, 8, 2837, 7, 10118, "ランドソル市街地", 20063115, 0);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2, 1, "ジュンとの出会い", "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 91002, 5118064, "黄金色の悩みごと", 40, 8, 4108402, 18, 10118, "フリーマーケット会場", 20063115, 0);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2, 1, "カオリとの出会い", "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 91002, 5118065, "白熱！　格闘大会！", 40, 8, 4107402, 18, 10118, "フリーマーケット会場", 20063115, 0);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (2, 1, "ニノンとの出会い", "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 91002, 5118066, "祭り太鼓はオーエドの華", 40, 8, 9000227, 16, 10118, "オーエド町", 20063115, 1);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (3, 1, "スズナとの出会い", "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 91002, 5118067, "人気者は遅れて\nやってくる", 40, 8, 2101181, 19, 10118, "フリーマーケット会場", 20063115, 0);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (3, 1, "ナナカとの出会い", "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 91002, 5118068, "巫女・ミーツ・魔法少女", 40, 8, 4109402, 18, 10118, "ランドソル市街地", 20063115, 0);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (3, 1, "キャル＆コッコロとの出会い", "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 91002, 5118069, "ネズ耳は二度なくなる", 40, 8, 4305402, 18, 10118, "フリーマーケット会場", 20063115, 0);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (3, 1, "ユカリとの出会い", "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 91002, 5118070, "この出会いにカンパイ！", 40, 8, 4101402, 18, 10118, "ランドソル市街地", 20063115, 0);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (3, 1, "アオイとの出会い", "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 91002, 5118071, "陰陽アンサンブル", 40, 8, 4106402, 18, 10118, "ランドソル市街地", 20063115, 0);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (3, 1, "シノブとの出会い", "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 91002, 5118072, "運試し十番勝負！", 40, 8, 2836, 7, 10118, "フリーマーケット会場", 20063115, 1);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (1, 0, "オープニング", 0, 0, 5118600, "彼女たちの新たな日常", 0, 0, 0, 0, 10118, 0, 20063115, 0);
